#include <bits/stdc++.h>
#define int long long
using namespace std;
int qpow (int a, int b, int p) {
	int res = 1;
	while (b) {
		if (b & 1) {
			res = res * a % p;
		}
		a = a * a % p;
		b >>= 1;
	}
	return res;
}
int BSGS (int a, int b, int p) {
	a %= p;
	b %= p;
	if (b == 1) {
		return 0;
	}
	int m = ceil (sqrt (p));
	int t = b;
	unordered_map <int, int> mp;
	for (int j = 0; j < m; j++) {
		mp[t] = j;
		t = t * a % p;
	}
	int mi = qpow (a, m, p);
	t = 1;
	for (int i = 1; i <= m; i++) {
		t = t * mi % p;
		if (mp.count (t)) {
			return i * m - mp[t];
		}
	}
	return -1;
}
signed main() {
	int p, b, n;
	cin >> p >> b >> n;
	if (!(b % p)) {
		cout << "no solution";
		return 0;
	}
	int ans = BSGS(b, n, p);
	if (ans == -1) {
		cout << "no solution";
	} else {
		cout << ans;
	}
	return 0;
}
